   196→template <class S, class F, class RQ, class RS>
   197→void GrpcMuxImpl<S, F, RQ, RS>::removeWatch(const std::string& type_url, Watch* watch) {
   198→  updateWatch(type_url, watch, {}, {});
   199→  watchMapFor(type_url).removeWatch(watch);
   200→}
