   207→template <class S, class F, class RQ, class RS>
   208→ScopedResume GrpcMuxImpl<S, F, RQ, RS>::pause(const std::vector<std::string> type_urls) {
   209→  for (const auto& type_url : type_urls) {
   210→    pausable_ack_queue_.pause(type_url);
   211→  }
   212→
   213→  return std::make_unique<Cleanup>([this, type_urls]() {
   214→    for (const auto& type_url : type_urls) {
   215→      pausable_ack_queue_.resume(type_url);
   216→      trySendDiscoveryRequests();
   217→    }
   218→  });
   219→}
