   221→template <class S, class F, class RQ, class RS>
   222→void GrpcMuxImpl<S, F, RQ, RS>::sendGrpcMessage(RQ& msg_proto, S& sub_state) {
   223→  if (sub_state.dynamicContextChanged() || !anyRequestSentYetInCurrentStream() ||
   224→      !skipSubsequentNode()) {
   225→    msg_proto.mutable_node()->CopyFrom(localInfo().node());
   226→  }
   227→  sendMessage(msg_proto);
   228→  setAnyRequestSentYetInCurrentStream(true);
   229→  sub_state.clearDynamicContextChanged();
