   232→template <class S, class F, class RQ, class RS>
   233→void GrpcMuxImpl<S, F, RQ, RS>::genericHandleResponse(const std::string& type_url,
   234→                                                      const RS& response_proto,
   235→                                                      ControlPlaneStats& control_plane_stats) {
   236→  auto sub = subscriptions_.find(type_url);
   237→  if (sub == subscriptions_.end()) {
   238→    ENVOY_LOG(warn,
   239→              "The server sent an xDS response proto with type_url {}, which we have "
   240→              "not subscribed to. Ignoring.",
   241→              type_url);
   242→    return;
   243→  }
   244→
   245→  if (response_proto.has_control_plane()) {
   246→    control_plane_stats.identifier_.set(response_proto.control_plane().identifier());
   247→
   248→    if (response_proto.control_plane().identifier() != sub->second->controlPlaneIdentifier()) {
   249→      sub->second->setControlPlaneIdentifier(response_proto.control_plane().identifier());
   250→      ENVOY_LOG(debug, "Receiving gRPC updates for {} from {}", response_proto.type_url(),
   251→                sub->second->controlPlaneIdentifier());
   252→    }
   253→  }
   254→
   255→  pausable_ack_queue_.push(sub->second->handleResponse(response_proto));
   256→  trySendDiscoveryRequests();
   257→  Memory::Utils::tryShrinkHeap();
   258→}
