   322→template <class S, class F, class RQ, class RS>
   323→void GrpcMuxImpl<S, F, RQ, RS>::trySendDiscoveryRequests() {
   324→  if (shutdown_) {
   325→    return;
   326→  }
   327→
   328→  while (true) {
   329→    // Do any of our subscriptions even want to send a request?
   330→    absl::optional<std::string> request_type_if_any = whoWantsToSendDiscoveryRequest();
   331→    if (!request_type_if_any.has_value()) {
   332→      break;
   333→    }
   334→    // If so, which one (by type_url)?
   335→    std::string next_request_type_url = request_type_if_any.value();
   336→    auto& sub = subscriptionStateFor(next_request_type_url);
   337→    ENVOY_LOG(debug, "GrpcMuxImpl wants to send discovery request for {}", next_request_type_url);
   338→    // Try again later if paused/rate limited/stream down.
   339→    if (!canSendDiscoveryRequest(next_request_type_url)) {
   340→      break;
   341→    }
   342→    std::unique_ptr<RQ> request;
   343→    // Get our subscription state to generate the appropriate discovery request, and send.
   344→    if (!pausable_ack_queue_.empty()) {
   345→      // Because ACKs take precedence over plain requests, if there is anything in the queue, it's
   346→      // safe to assume it's of the type_url that we're wanting to send.
   347→      //
   348→      // getNextRequestWithAck() returns a raw unowned pointer, which sendGrpcMessage deletes.
   349→      request = sub.getNextRequestWithAck(pausable_ack_queue_.popFront());
   350→      ENVOY_LOG(debug, "GrpcMuxImpl sent ACK discovery request for {}", next_request_type_url);
   351→    } else {
   352→      // Returns a raw unowned pointer, which sendGrpcMessage deletes.
   353→      request = sub.getNextRequestAckless();
   354→      ENVOY_LOG(debug, "GrpcMuxImpl sent non-ACK discovery request for {}", next_request_type_url);
   355→    }
   356→    ENVOY_LOG(debug, "GrpcMuxImpl skip_subsequent_node: {}", skipSubsequentNode());
   357→    sendGrpcMessage(*request, sub);
   358→  }
   359→  maybeUpdateQueueSizeStat(pausable_ack_queue_.size());
   360→}
