   362→// Checks whether external conditions allow sending a discovery request. (Does not check
   363→// whether we *want* to send a discovery request).
   364→template <class S, class F, class RQ, class RS>
   365→bool GrpcMuxImpl<S, F, RQ, RS>::canSendDiscoveryRequest(const std::string& type_url) {
   366→  RELEASE_ASSERT(
   367→      !pausable_ack_queue_.paused(type_url),
   368→      fmt::format("canSendDiscoveryRequest() called on paused type_url {}. Pausedness is "
   369→                  "supposed to be filtered out by whoWantsToSendDiscoveryRequest(). ",
   370→                  type_url));
   371→
   372→  if (!grpcStreamAvailable()) {
   373→    ENVOY_LOG(trace, "No stream available to send a discovery request for {}.", type_url);
   374→    return false;
   375→  } else if (!rateLimitAllowsDrain()) {
   376→    ENVOY_LOG(trace, "{} discovery request hit rate limit; will try later.", type_url);
   377→    return false;
   378→  }
   379→  return true;
   380→}
