   382→// Checks whether we have something to say in a discovery request, which can be an ACK and/or
   383→// a subscription update. (Does not check whether we *can* send that discovery request).
   384→// Returns the type_url we should send the discovery request for (if any).
   385→// First, prioritizes ACKs over non-ACK subscription interest updates.
   386→// Then, prioritizes non-ACK updates in the order the various types
   387→// of subscriptions were activated.
   388→template <class S, class F, class RQ, class RS>
   389→absl::optional<std::string> GrpcMuxImpl<S, F, RQ, RS>::whoWantsToSendDiscoveryRequest() {
   390→  // All ACKs are sent before plain updates. trySendDiscoveryRequests() relies on this. So, choose
   391→  // type_url from pausable_ack_queue_ if possible, before looking at pending updates.
   392→  if (!pausable_ack_queue_.empty()) {
   393→    return pausable_ack_queue_.front().type_url_;
   394→  }
   395→  // If we're looking to send multiple non-ACK requests, send them in the order that their
   396→  // subscriptions were initiated.
   397→  for (const auto& sub_type : subscription_ordering_) {
   398→    auto& sub = subscriptionStateFor(sub_type);
   399→    if (sub.subscriptionUpdatePending() && !pausable_ack_queue_.paused(sub_type)) {
   400→      return sub_type;
   401→    }
   402→  }
   403→  return absl::nullopt;
   404→}
