   123→bool DeltaSubscriptionState::isHeartbeatResource(
   124→    const envoy::service::discovery::v3::Resource& resource) const {
   125→  if (!supports_heartbeats_) {
   126→    return false;
   127→  }
   128→  if (resource.has_resource()) {
   129→    return false;
   130→  }
   131→
   132→  if (const auto maybe_resource = getRequestedResourceState(resource.name());
   133→      maybe_resource.has_value()) {
   134→    return !maybe_resource->isWaitingForServer() && resource.version() == maybe_resource->version();
   135→  }
   136→
   137→  if (const auto itr = wildcard_resource_state_.find(resource.name());
   138→      itr != wildcard_resource_state_.end()) {
   139→    return resource.version() == itr->second;
   140→  }
   141→
   142→  if (const auto itr = ambiguous_resource_state_.find(resource.name());
   143→      itr != ambiguous_resource_state_.end()) {
   144→    // In theory we should move the ambiguous resource to wildcard, because probably we shouldn't be
   145→    // getting heartbeat responses about resources that we are not interested in, but the server
   146→    // could have sent this heartbeat before it learned about our lack of interest in the resource.
   147→    return resource.version() == itr->second;
   148→  }
   149→
   150→  return false;
   151→}
