   153→void DeltaSubscriptionState::handleGoodResponse(
   154→    const envoy::service::discovery::v3::DeltaDiscoveryResponse& message) {
   155→  absl::flat_hash_set<std::string> names_added_removed;
   156→  Protobuf::RepeatedPtrField<envoy::service::discovery::v3::Resource> non_heartbeat_resources;
