   158→    if (!names_added_removed.insert(resource.name()).second) {
   159→      throw EnvoyException(
   160→          fmt::format("duplicate name {} found among added/updated resources", resource.name()));
   161→    }
   162→    if (isHeartbeatResource(resource)) {
   163→      continue;
   164→    }
   165→    // TODO (dmitri-d) consider changing onConfigUpdate callback interface to avoid copying of
   166→    // resources
   167→    non_heartbeat_resources.Add()->CopyFrom(resource);
   168→    // DeltaDiscoveryResponses for unresolved aliases don't contain an actual resource
   169→    if (!resource.has_resource() && resource.aliases_size() > 0) {
   170→      continue;
   171→    }
   172→    if (message.type_url() != resource.resource().type_url()) {
   173→      throw EnvoyException(fmt::format("type URL {} embedded in an individual Any does not match "
   174→                                       "the message-wide type URL {} in DeltaDiscoveryResponse {}",
   175→                                       resource.resource().type_url(), message.type_url(),
   176→                                       message.DebugString()));
   177→    }
   178→  }
   179→  for (const auto& name : message.removed_resources()) {
   180→    if (!names_added_removed.insert(name).second) {
   181→      throw EnvoyException(
   182→          fmt::format("duplicate name {} found in the union of added+removed resources", name));
   183→    }
   184→  }
   185→
   186→  callbacks().onConfigUpdate(non_heartbeat_resources, message.removed_resources(),
   187→                             message.system_version_info());
   188→
   189→  // Processing point when resources are successfully ingested.
   190→  if (xds_config_tracker_.has_value()) {
   191→    xds_config_tracker_->onConfigAccepted(message.type_url(), non_heartbeat_resources,
   192→                                          message.removed_resources());
   193→  }
   194→
   195→  {
   196→    const auto scoped_update = ttl_.scopedTtlUpdate();
   197→    if (requested_resource_state_.contains(Wildcard)) {
   198→      for (const auto& resource : message.resources()) {
   199→        addResourceStateFromServer(resource);
   200→      }
   201→    } else {
   202→      // We are not subscribed to wildcard, so we only take resources that we explicitly requested
   203→      // and ignore the others.
   204→      // NOTE: This is not gonna work for xdstp resources with glob resource matching.
   205→      for (const auto& resource : message.resources()) {
   206→        if (requested_resource_state_.contains(resource.name())) {
