   281→bool DeltaSubscriptionState::isInitialRequestForLegacyWildcard() {
   282→  if (in_initial_legacy_wildcard_) {
   283→    requested_resource_state_.insert_or_assign(Wildcard, ResourceState::waitingForServer());
