   314→void DeltaSubscriptionState::addResourceStateFromServer(
   315→    const envoy::service::discovery::v3::Resource& resource) {
   316→  setResourceTtl(resource);
   317→
   318→  if (auto maybe_resource = getRequestedResourceState(resource.name());
   319→      maybe_resource.has_value()) {
   320→    // It is a resource that we requested.
   321→    maybe_resource->setVersion(resource.version());
   322→    ASSERT(requested_resource_state_.contains(resource.name()));
   323→    ASSERT(!wildcard_resource_state_.contains(resource.name()));
   324→    ASSERT(!ambiguous_resource_state_.contains(resource.name()));
