   329→    // is resolved.
   330→    ambiguous_resource_state_.erase(resource.name());
   331→    ASSERT(!requested_resource_state_.contains(resource.name()));
   332→    ASSERT(wildcard_resource_state_.contains(resource.name()));
   333→    ASSERT(!ambiguous_resource_state_.contains(resource.name()));
   334→  }
