   337→void DeltaSubscriptionState::setResourceTtl(
   338→    const envoy::service::discovery::v3::Resource& resource) {
   339→  if (resource.has_ttl()) {
   340→    ttl_.add(std::chrono::milliseconds(DurationUtil::durationToMilliseconds(resource.ttl())),
   341→             resource.name());
