   217→void WatchMap::onConfigUpdate(
   218→    const Protobuf::RepeatedPtrField<envoy::service::discovery::v3::Resource>& added_resources,
   219→    const Protobuf::RepeatedPtrField<std::string>& removed_resources,
   220→    const std::string& system_version_info) {
   221→  // Track any removals triggered by earlier watch updates.
   222→  ASSERT(deferred_removed_during_update_ == nullptr);
   223→  deferred_removed_during_update_ = std::make_unique<absl::flat_hash_set<Watch*>>();
   224→  Cleanup cleanup([this] { removeDeferredWatches(); });
   225→  // Build a pair of maps: from watches, to the set of resources {added,removed} that each watch
   226→  // cares about. Each entry in the map-pair is then a nice little bundle that can be fed directly
   227→  // into the individual onConfigUpdate()s.
   228→  std::vector<DecodedResourcePtr> decoded_resources;
   229→  absl::flat_hash_map<Watch*, std::vector<DecodedResourceRef>> per_watch_added;
   230→  for (const auto& r : added_resources) {
   231→    const absl::flat_hash_set<Watch*>& interested_in_r = watchesInterestedIn(r.name());
   232→    // If there are no watches, then we don't need to decode. If there are watches, they should all
   233→    // be for the same resource type, so we can just use the callbacks of the first watch to decode.
   234→    if (interested_in_r.empty()) {
   235→      continue;
   236→    }
   237→    decoded_resources.emplace_back(
   238→        new DecodedResourceImpl((*interested_in_r.begin())->resource_decoder_, r));
   239→    for (const auto& interested_watch : interested_in_r) {
   240→      per_watch_added[interested_watch].emplace_back(*decoded_resources.back());
   241→    }
   242→  }
   243→  absl::flat_hash_map<Watch*, Protobuf::RepeatedPtrField<std::string>> per_watch_removed;
   244→  for (const auto& r : removed_resources) {
   245→    const absl::flat_hash_set<Watch*>& interested_in_r = watchesInterestedIn(r);
   246→    for (const auto& interested_watch : interested_in_r) {
   247→      *per_watch_removed[interested_watch].Add() = r;
   248→    }
   249→  }
   250→
   251→  // Execute external config validators.
   252→  config_validators_.executeValidators(type_url_, decoded_resources, removed_resources);
   253→
   254→  // We just bundled up the updates into nice per-watch packages. Now, deliver them.
   255→  for (const auto& [cur_watch, resource_to_add] : per_watch_added) {
   256→    if (deferred_removed_during_update_->count(cur_watch) > 0) {
   257→      continue;
   258→    }
   259→    const auto removed = per_watch_removed.find(cur_watch);
   260→    if (removed == per_watch_removed.end()) {
   261→      // additions only, no removals
   262→      THROW_IF_NOT_OK(
   263→          cur_watch->callbacks_.onConfigUpdate(resource_to_add, {}, system_version_info));
   264→    } else {
   265→      // both additions and removals
   266→      THROW_IF_NOT_OK(cur_watch->callbacks_.onConfigUpdate(resource_to_add, removed->second,
   267→                                                           system_version_info));
   268→      // Drop the removals now, so the final removals-only pass won't use them.
   269→      per_watch_removed.erase(removed);
   270→    }
   271→  }
   272→  // Any removals-only updates will not have been picked up in the per_watch_added loop.
   273→  for (auto& [cur_watch, resource_to_remove] : per_watch_removed) {
   274→    if (deferred_removed_during_update_->count(cur_watch) > 0) {
   275→      continue;
   276→    }
   277→    THROW_IF_NOT_OK(
   278→        cur_watch->callbacks_.onConfigUpdate({}, resource_to_remove, system_version_info));
   279→  }
   280→  // notify empty update
   281→  if (added_resources.empty() && removed_resources.empty()) {
   282→    for (auto& cur_watch : wildcard_watches_) {
   283→      THROW_IF_NOT_OK(cur_watch->callbacks_.onConfigUpdate({}, {}, system_version_info));
   284→    }
   285→  }
   286→
   287→  if (eds_resources_cache_.has_value()) {
   288→    // Add/update the watched resources to/in the cache.
   289→    for (const auto& resource : decoded_resources) {
   290→      const envoy::config::endpoint::v3::ClusterLoadAssignment& cluster_load_assignment =
   291→          dynamic_cast<const envoy::config::endpoint::v3::ClusterLoadAssignment&>(
   292→              resource->resource());
   293→      eds_resources_cache_->setResource(resource->name(), cluster_load_assignment);
   294→    }
   295→    // No need to remove resources from the cache, as currently only non-collection
   296→    // subscriptions are supported, and these resources are removed in the call
   297→    // to updateWatchInterest().
   298→  }
   299→}

